import { NextRequest } from 'next/server'
import OpenAI from 'openai'
import { getPrompts } from '@/lib/ai/prompts'
import { searchWeb, searchMultiple, formatSearchResultsAsContext, buildSourcesBlock } from '@/lib/ai/search'
import { supabase } from '@/lib/supabase/server'
import { apiError } from '@/lib/api-utils'

// Helper to emit SSE phase events
function phaseEvent(phase: string, status: string, detail?: string, meta?: Record<string, unknown>) {
    return `event: phase\ndata: ${JSON.stringify({ phase, status, detail, ...meta })}\n\n`
}

export async function POST(request: NextRequest) {
    try {
        const { message, customization, files, queryMode, webSearch, thinking, deepResearch, projectId, conversationId } = await request.json()

        let userContent = message || ''

        // 1. Context Injection from Project Files
        if (projectId) {
            const { data: projectFiles } = await supabase
                .from('files')
                .select('name, extracted_text')
                .eq('project_id', projectId)
                .not('extracted_text', 'is', null) // Only files with text

            if (projectFiles && projectFiles.length > 0) {
                userContent += `\n\n--- PROJECT CONTEXT (${projectFiles.length} files) ---\n`
                projectFiles.forEach(f => {
                    // Truncate if too large to avoid hitting hard limits immediately, 
                    // though gpt-4o-mini has 128k context. Let's be safe but generous.
                    // 20k chars per file approx.
                    const text = f.extracted_text?.slice(0, 20000) || ''
                    userContent += `\nFILE: ${f.name}\nCONTENT:\n${text}\n----------------\n`
                })
                userContent += `\n[INSTRUCTION: Use the above PROJECT CONTEXT to answer the user's query. Cite specific files if relevant.]`
            }
        }

        if (files && files.length > 0) {
            const fileNames = files.map((f: any) => typeof f === 'string' ? f : f.name).join(', ')
            userContent += `\n\n[User uploaded files in this message: ${fileNames}]`

            // Iterate through files and inject content if available
            files.forEach((f: any) => {
                if (typeof f === 'object' && f.content) {
                    userContent += `\n--- FILE: ${f.name} ---\n${f.content.slice(0, 20000)}\n----------------\n`
                }
            })

            if (!message) {
                userContent += '\nPlease analyze these files.'
            }
        }

        // Determine model and token limits based on mode
        let model = 'gpt-4o-mini' // Default & requested cost-safe standard
        let maxTokens = 800

        if (deepResearch) {
            maxTokens = 4000
        } else if (thinking) {
            maxTokens = 2000
        } else if (webSearch) {
            maxTokens = 1500
        }

        const apiKey = process.env.OPENAI_API_KEY
        if (!apiKey) {
            return apiError('AI service is not configured', 503)
        }

        const client = new OpenAI({ apiKey })
        const encoder = new TextEncoder()

        const readable = new ReadableStream({
            async start(controller) {
                try {
                    let searchContext = ''
                    let sourcesBlock = ''
                    let thinkingPlan = ''

                    // ═══════════════════════════════════════════════
                    // DEEP RESEARCH — Real Pipeline V1
                    // ═══════════════════════════════════════════════
                    if (deepResearch) {
                        // Stage 1: Research Planning (Multi-Query Generation)
                        controller.enqueue(encoder.encode(phaseEvent('research_planning', 'start', 'Defining comprehensive research strategy')))

                        const queryGenResponse = await client.chat.completions.create({
                            model: 'gpt-4o-mini',
                            messages: [
                                {
                                    role: 'system',
                                    content: 'You are a legal research strategist. Generate 4 complementary, high-intent search queries to investigate this issue from multiple angles (statutory, case law, jurisdictional, and practical). Return ONLY a JSON array of strings.'
                                },
                                { role: 'user', content: userContent }
                            ],
                            max_tokens: 300,
                            temperature: 0.3
                        })

                        let searchQueries: string[] = [userContent]
                        try {
                            const raw = queryGenResponse.choices[0]?.message?.content || ''
                            const parsed = JSON.parse(raw)
                            if (Array.isArray(parsed)) searchQueries = parsed.slice(0, 4)
                        } catch { /* fallback to original */ }

                        controller.enqueue(encoder.encode(phaseEvent('research_planning', 'update', `Planned ${searchQueries.length} research vectors`, { queries: searchQueries })))

                        // Stage 2: Source Collection (Tavily Multi-Query)
                        controller.enqueue(encoder.encode(phaseEvent('source_collection', 'start', 'Retrieving authoritative legal sources using Tavily')))

                        const searchResponses = await searchMultiple(searchQueries, 5, 'advanced')
                        const totalResults = searchResponses.reduce((sum, r) => sum + r.results.length, 0)

                        const allDomains: string[] = []
                        for (const resp of searchResponses) {
                            for (const r of resp.results) {
                                try {
                                    const domain = new URL(r.url).hostname.replace('www.', '')
                                    if (!allDomains.includes(domain)) allDomains.push(domain)
                                } catch { /* skip */ }
                            }
                        }

                        controller.enqueue(encoder.encode(phaseEvent('source_collection', 'update', `Captured ${totalResults} sources from ${allDomains.length} domains`, { domains: allDomains, count: totalResults })))

                        // Stage 3: Reading & Extraction
                        controller.enqueue(encoder.encode(phaseEvent('reading_extraction', 'start', 'Extracting relevant passages and legal citations')))

                        searchContext = formatSearchResultsAsContext(searchResponses)
                        sourcesBlock = buildSourcesBlock(searchResponses)

                        controller.enqueue(encoder.encode(phaseEvent('reading_extraction', 'update', `Processed all found sources`)))

                        // Stage 4: Synthesis
                        controller.enqueue(encoder.encode(phaseEvent('synthesis', 'start', 'Synthesizing research into a coherent legal analysis')))

                        // Internal synthesis planning to ensure quality
                        const synthesisPlanResponse = await client.chat.completions.create({
                            model: 'gpt-4o-mini',
                            messages: [
                                {
                                    role: 'system',
                                    content: 'Analyze the following research and create a structured synthesis of the key findings. Resolve any conflicting information. Outline the core legal conclusions.'
                                },
                                { role: 'user', content: `Original Query: ${userContent}\n\nSearch context:\n${searchContext}` }
                            ],
                            max_tokens: 600,
                            temperature: 0.3
                        })

                        thinkingPlan = `SYNTHESIS PLAN:\n${synthesisPlanResponse.choices[0]?.message?.content || ''}`
                        controller.enqueue(encoder.encode(phaseEvent('synthesis', 'update', 'Organized research into key themes and precedents')))

                        // Stage 5: Drafting
                        controller.enqueue(encoder.encode(phaseEvent('drafting', 'start', 'Drafting final integrated legal answer')))

                        // ═══════════════════════════════════════════════
                        // WEB SEARCH — Real Pipeline V1
                        // ═══════════════════════════════════════════════
                    } else if (webSearch) {
                        controller.enqueue(encoder.encode(phaseEvent('research_planning', 'start', 'Optimizing search queries')))

                        const queryGenResponse = await client.chat.completions.create({
                            model: 'gpt-4o-mini',
                            messages: [
                                {
                                    role: 'system',
                                    content: 'Generate 2 complementary search queries for this topic. Return ONLY a JSON array of strings.'
                                },
                                { role: 'user', content: userContent }
                            ],
                            max_tokens: 200,
                            temperature: 0.3
                        })

                        let searchQueries: string[] = [userContent]
                        try {
                            const raw = queryGenResponse.choices[0]?.message?.content || ''
                            const parsed = JSON.parse(raw)
                            if (Array.isArray(parsed)) searchQueries = parsed.slice(0, 2)
                        } catch { /* fallback */ }

                        controller.enqueue(encoder.encode(phaseEvent('searching_web', 'start', 'Searching via Tavily')))

                        const searchResponses = await searchMultiple(searchQueries, 4, 'basic')
                        const totalResults = searchResponses.reduce((sum, r) => sum + r.results.length, 0)

                        const domains = [...new Set(searchResponses.flatMap(resp => resp.results.map(r => {
                            try { return new URL(r.url).hostname.replace('www.', '') } catch { return '' }
                        }).filter(Boolean)))]

                        controller.enqueue(encoder.encode(phaseEvent('searching_web', 'update', `Found ${totalResults} relevant sites`, { domains, count: totalResults })))

                        controller.enqueue(encoder.encode(phaseEvent('reading_sources', 'start', 'Reading source snippets')))
                        searchContext = formatSearchResultsAsContext(searchResponses)
                        sourcesBlock = buildSourcesBlock(searchResponses)
                        controller.enqueue(encoder.encode(phaseEvent('reading_sources', 'update', 'Extracted key information')))

                        controller.enqueue(encoder.encode(phaseEvent('drafting', 'start', 'Formulating answer')))

                        // ═══════════════════════════════════════════════
                        // THINKING — Real Pipeline V1
                        // ═══════════════════════════════════════════════
                    } else if (thinking) {
                        controller.enqueue(encoder.encode(phaseEvent('thinking', 'start', 'Analyzing complex reasoning paths')))

                        const planResponse = await client.chat.completions.create({
                            model: 'gpt-4o-mini',
                            messages: [
                                {
                                    role: 'system',
                                    content: `You are a legal reasoning agent. Break down this question into a logical reasoning chain. Consider conflicting views and jurisdictional nuances. Output a detailed internal plan (max 300 words).`
                                },
                                { role: 'user', content: userContent }
                            ],
                            max_tokens: 500,
                            temperature: 0.3
                        })

                        thinkingPlan = planResponse.choices[0]?.message?.content || ''

                        controller.enqueue(encoder.encode(phaseEvent('thinking', 'update', 'Constructed internal logic chain')))
                        controller.enqueue(encoder.encode(phaseEvent('drafting', 'start', 'Applying reasoning to final response')))

                    } else {
                        // Default
                        controller.enqueue(encoder.encode(phaseEvent('thinking', 'start', 'Analyzing query')))
                        controller.enqueue(encoder.encode(phaseEvent('drafting', 'start', 'Preparing response')))
                    }

                    // ═══════════════════════════════════════════════
                    // BUILD THE FINAL PROMPT & STREAM RESPONSE
                    // ═══════════════════════════════════════════════
                    const { systemPrompt, userPrompt } = getPrompts('assistant_chat', {
                        message: userContent,
                        customization,
                        queryMode,
                        webSearch,
                        thinking,
                        deepResearch
                    })

                    const messages: OpenAI.Chat.Completions.ChatCompletionMessageParam[] = [
                        { role: 'system', content: systemPrompt }
                    ]

                    if (searchContext) {
                        messages.push({
                            role: 'system',
                            content: `Here are real web search results to base your answer on. Use these as your primary source of information and cite them using inline numbered citations [1], [2], etc.:\n\n${searchContext}`
                        })
                    }

                    if (thinkingPlan) {
                        messages.push({
                            role: 'system',
                            content: `Here is your internal analysis plan. Follow this structure to create a thorough response, but do NOT show this plan to the user:\n\n${thinkingPlan}`
                        })
                    }

                    messages.push({ role: 'user', content: userPrompt })

                    const stream = await client.chat.completions.create({
                        model,
                        messages,
                        max_tokens: maxTokens,
                        temperature: 0.4,
                        stream: true
                    })

                    let streamedContent = ''
                    for await (const chunk of stream) {
                        const content = chunk.choices[0]?.delta?.content || ''
                        if (content) {
                            streamedContent += content
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content })}\n\n`))
                        }
                    }

                    if (sourcesBlock && !streamedContent.includes('<!--SOURCES:')) {
                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content: sourcesBlock })}\n\n`))
                    }

                    // Save assistant message to database if we have a conversationId
                    if (conversationId && streamedContent) {
                        try {
                            const { error: saveError } = await supabase
                                .from('messages')
                                .insert({
                                    conversation_id: conversationId,
                                    role: 'assistant',
                                    content: sourcesBlock ? `${streamedContent}\n\n${sourcesBlock}` : streamedContent
                                })

                            if (saveError) {
                                console.error('Failed to save assistant message:', saveError)
                            }
                        } catch (e) {
                            console.error('Error saving assistant message:', e)
                        }
                    }

                    controller.enqueue(encoder.encode(phaseEvent('complete', 'end')))
                    controller.enqueue(encoder.encode('data: [DONE]\n\n'))
                    controller.close()
                } catch (err) {
                    console.error('Stream error:', err)
                    try {
                        controller.enqueue(encoder.encode(phaseEvent('error', 'error', 'Something went wrong while processing')))
                        controller.enqueue(encoder.encode('data: [DONE]\n\n'))
                        controller.close()
                    } catch (e) {
                        // Controller might already be closed or errored
                        console.error('Failed to close controller safely:', e)
                    }
                }
            }
        })

        return new Response(readable, {
            headers: {
                'Content-Type': 'text/event-stream',
                'Cache-Control': 'no-cache',
                'Connection': 'keep-alive',
            }
        })
    } catch (error) {
        return apiError('Internal server error', 500, error)
    }
}

import { NextRequest, NextResponse } from 'next/server'
import { callAISafe } from '@/lib/ai/client'
import { supabase } from '@/lib/supabase/server'

interface RouteParams {
    params: Promise<{ id: string; fileId: string }>
}

// POST /api/vault/projects/[id]/files/[fileId]/analyze
// Body: { action: 'summarize' | 'analyze', text: string }
export async function POST(request: NextRequest, { params }: RouteParams) {
    try {
        const { id: projectId, fileId } = await params
        const { action, text } = await request.json()

        if (!action || !text) {
            return NextResponse.json(
                { error: 'Action and text are required' },
                { status: 400 }
            )
        }

        if (action !== 'summarize' && action !== 'analyze') {
            return NextResponse.json(
                { error: 'Action must be "summarize" or "analyze"' },
                { status: 400 }
            )
        }

        const useCase = action === 'summarize' ? 'document_summary' : 'document_analysis'

        const { result, error } = await callAISafe(useCase as 'document_summary' | 'document_analysis', {
            text
        })

        if (error) {
            return NextResponse.json({ error }, { status: 503 })
        }

        // Optionally store the analysis result linked to the file
        // (Using a simple approach — store in file metadata or a new table)
        console.log(`[Vault AI] project=${projectId} file=${fileId} action=${action}`)

        return NextResponse.json({
            fileId,
            action,
            result
        })
    } catch (error: unknown) {
        const message = error instanceof Error ? error.message : 'Failed to analyze document'
        console.error('Document analysis error:', message)
        return NextResponse.json({ error: message }, { status: 500 })
    }
}

"use client"

import { useState } from "react"
import { VaultHeader } from "@/components/vault/vault-header"
import { CreateProjectCard } from "@/components/vault/create-project-card"
import { ProjectCard } from "@/components/vault/project-card"
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { toast } from "sonner"

import { useVault } from "@/context/vault-context"
import { Project } from "@/types"
import { useRouter } from "next/navigation"

export default function VaultPage() {
    const { projects, addProject, renameProject, deleteProject } = useVault()
    const router = useRouter()

    const [isCreateOpen, setIsCreateOpen] = useState(false)
    const [isRenameOpen, setIsRenameOpen] = useState(false)
    const [isDeleteOpen, setIsDeleteOpen] = useState(false)
    const [currentProject, setCurrentProject] = useState<Project | null>(null)
    const [projectNameInput, setProjectNameInput] = useState("")

    const handleCreateProject = () => {
        if (!projectNameInput.trim()) return
        addProject(projectNameInput)
        setIsCreateOpen(false)
        setProjectNameInput("")
    }

    const openRenameDialog = (id: string, currentTitle: string) => {
        const project = projects.find(p => p.id === id)
        if (project) {
            setCurrentProject(project)
            setProjectNameInput(currentTitle)
            setIsRenameOpen(true)
        }
    }

    const handleRenameProject = () => {
        if (!currentProject || !projectNameInput.trim()) return

        renameProject(currentProject.id, projectNameInput)

        setIsRenameOpen(false)
        setCurrentProject(null)
        setProjectNameInput("")
    }

    const openDeleteDialog = (id: string) => {
        const project = projects.find(p => p.id === id)
        if (project) {
            setCurrentProject(project)
            setIsDeleteOpen(true)
        }
    }

    const handleDeleteProject = () => {
        if (!currentProject) return

        deleteProject(currentProject.id)
        setIsDeleteOpen(false)
        setCurrentProject(null)
    }

    const handleProjectClick = (projectId: string) => {
        router.push(`/vault/${projectId}`)
    }

    return (
        <div className="flex flex-col flex-1 w-full max-w-[1600px] mx-auto p-3 sm:p-4 md:p-6 space-y-6 md:space-y-8 h-full overflow-y-auto">
            <VaultHeader />

            <div className="space-y-3 md:space-y-4">
                <h2 className="text-base sm:text-lg font-medium">Your projects</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 md:gap-4" id="project-grid">
                    <CreateProjectCard onClick={() => {
                        setProjectNameInput("")
                        setIsCreateOpen(true)
                    }} />

                    {projects.map((project) => (
                        <div key={project.id} onClick={() => handleProjectClick(project.id)}>
                            <ProjectCard
                                id={project.id}
                                title={project.title}
                                organization={project.organization}
                                fileCount={project.fileCount}
                                queryCount={project.queryCount}
                                icon={project.icon}
                                isSecured={project.isSecured}
                                onRename={openRenameDialog}
                                onDelete={(id) => {
                                    // Prevent navigation when clicking delete
                                    openDeleteDialog(id)
                                }}
                            />
                        </div>
                    ))}
                </div>
            </div>

            {/* Create Project Dialog */}
            <Dialog open={isCreateOpen} onOpenChange={setIsCreateOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Create Project</DialogTitle>
                        <DialogDescription>Enter a name for your new project.</DialogDescription>
                    </DialogHeader>
                    <div className="py-4">
                        <label htmlFor="create-name" className="mb-2 block text-sm font-medium">Project Name</label>
                        <Input
                            id="create-name"
                            value={projectNameInput}
                            onChange={(e) => setProjectNameInput(e.target.value)}
                            placeholder="e.g., Merger Analysis 2024"
                            onKeyDown={(e) => e.key === "Enter" && handleCreateProject()}
                        />
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsCreateOpen(false)}>Cancel</Button>
                        <Button onClick={handleCreateProject} disabled={!projectNameInput.trim()}>Create</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Rename Project Dialog */}
            <Dialog open={isRenameOpen} onOpenChange={setIsRenameOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Rename Project</DialogTitle>
                        <DialogDescription>Enter a new name for this project.</DialogDescription>
                    </DialogHeader>
                    <div className="py-4">
                        <label htmlFor="rename-name" className="mb-2 block text-sm font-medium">Project Name</label>
                        <Input
                            id="rename-name"
                            value={projectNameInput}
                            onChange={(e) => setProjectNameInput(e.target.value)}
                            onKeyDown={(e) => e.key === "Enter" && handleRenameProject()}
                        />
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsRenameOpen(false)}>Cancel</Button>
                        <Button onClick={handleRenameProject} disabled={!projectNameInput.trim()}>Save Changes</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            {/* Delete Confirmation Dialog */}
            <Dialog open={isDeleteOpen} onOpenChange={setIsDeleteOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Delete Project?</DialogTitle>
                        <DialogDescription>
                            Are you sure you want to delete{" "}
                            <span className="font-semibold text-foreground">“{currentProject?.title}”</span>?
                            This action cannot be undone and all associated files will be removed.
                        </DialogDescription>
                    </DialogHeader>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsDeleteOpen(false)}>Cancel</Button>
                        <Button variant="destructive" onClick={handleDeleteProject}>Delete Project</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

"use client"

import { useEffect, useState } from "react"
import { MessageSquare, FileText, Workflow, MoreHorizontal, ArrowRight, Folder, Trash2, ExternalLink, Calendar } from "lucide-react"
import { HistoryItem } from "@/context/history-context"
import { Card, CardContent } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu"
import { Badge } from "@/components/ui/badge"
import { formatDistanceToNow } from "date-fns"
import { cn } from "@/lib/utils"

interface HistoryCardProps {
    item: HistoryItem
}

export function HistoryCard({ item }: HistoryCardProps) {
    const Icon = item.type === "vault" ? Folder : item.type === "workflow" ? Workflow : MessageSquare

    // Type-specific styles
    const typeStyles = {
        assistant: "text-blue-600 bg-blue-100 dark:bg-blue-900/40 dark:text-blue-400 border-blue-200 dark:border-blue-800",
        vault: "text-amber-600 bg-amber-100 dark:bg-amber-900/40 dark:text-amber-400 border-amber-200 dark:border-amber-800",
        workflow: "text-purple-600 bg-purple-100 dark:bg-purple-900/40 dark:text-purple-400 border-purple-200 dark:border-purple-800"
    }

    const typeLabel = {
        assistant: "Assistant",
        vault: "Vault Project",
        workflow: "Workflow"
    }

    return (
        <div className="group relative">
            <Card className="hover:shadow-md transition-all duration-200 border-border/50 hover:border-border cursor-pointer overflow-hidden">
                <CardContent className="p-0">
                    <div className="flex items-start gap-4 p-4 sm:p-5">
                        <div className={cn("shrink-0 p-2.5 rounded-xl border flex items-center justify-center", typeStyles[item.type])}>
                            <Icon className="w-5 h-5" />
                        </div>

                        <div className="flex-1 min-w-0 space-y-1">
                            <div className="flex items-center justify-between gap-2">
                                <h3 className="font-semibold text-base leading-none truncate group-hover:text-primary transition-colors">
                                    {item.title}
                                </h3>
                                <div className="flex items-center gap-2 shrink-0">
                                    <TimeDisplay date={item.date} />
                                    <DropdownMenu>
                                        <DropdownMenuTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 -mr-2 sm:mr-0 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                                                <MoreHorizontal className="w-4 h-4" />
                                            </Button>
                                        </DropdownMenuTrigger>
                                        <DropdownMenuContent align="end">
                                            <DropdownMenuItem>
                                                <ExternalLink className="w-4 h-4 mr-2" />
                                                Open
                                            </DropdownMenuItem>
                                            <DropdownMenuItem className="text-destructive focus:text-destructive">
                                                <Trash2 className="w-4 h-4 mr-2" />
                                                Delete
                                            </DropdownMenuItem>
                                        </DropdownMenuContent>
                                    </DropdownMenu>
                                </div>
                            </div>

                            <div className="flex items-center gap-2 overflow-hidden">
                                <Badge variant="secondary" className="text-xs font-normal shrink-0 px-1.5 py-0 h-5">
                                    {typeLabel[item.type]}
                                </Badge>
                                {item.subtitle && (
                                    <>
                                        <span className="text-muted-foreground/40 text-[10px]">•</span>
                                        <p className="text-sm text-muted-foreground truncate opacity-80">
                                            {item.subtitle}
                                        </p>
                                    </>
                                )}
                            </div>

                            <p className="text-sm text-foreground/70 line-clamp-2 mt-2 leading-relaxed">
                                {item.preview}
                            </p>

                            {/* Metadata Footer */}
                            {(item.meta?.fileCount || item.meta?.workflowId) && (
                                <div className="flex items-center gap-3 mt-3 pt-3 border-t border-dashed">
                                    {item.meta.fileCount && (
                                        <div className="flex items-center text-xs text-muted-foreground">
                                            <FileText className="w-3.5 h-3.5 mr-1" />
                                            {item.meta.fileCount} files
                                        </div>
                                    )}
                                    {item.meta.workflowId && (
                                        <div className="flex items-center text-xs text-muted-foreground uppercase tracking-wider font-medium">
                                            <Workflow className="w-3.5 h-3.5 mr-1" />
                                            {item.meta.workflowId}
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                    </div>
                </CardContent>
            </Card>
        </div>
    )
}

function TimeDisplay({ date }: { date: Date | number }) {
    const [_, setTick] = useState(0)

    useEffect(() => {
        const timer = setInterval(() => {
            setTick(t => t + 1)
        }, 30000)
        return () => clearInterval(timer)
    }, [])

    return (
        <span suppressHydrationWarning className="text-xs text-muted-foreground whitespace-nowrap">
            {formatDistanceToNow(date, { addSuffix: true })}
        </span>
    )
}

