"use client"

import { useState, useEffect } from "react"
import { useRouter, useSearchParams } from "next/navigation"
import { Button } from "@/components/ui/button"
// import { ScrollArea } from "@/components/ui/scroll-area" 
import { FileText, Upload, Trash2, Plus, Search, Loader2, MessageSquare } from "lucide-react"
import { useVault } from "@/context/vault-context"
import { Project } from "@/types"
import { Input } from "@/components/ui/input"
import { Separator } from "@/components/ui/separator"
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog"
import { toast } from "sonner"

interface ProjectSidebarProps {
    project: Project
}

export function ProjectSidebar({ project }: ProjectSidebarProps) {
    const { addFileToProject, removeFileFromProject } = useVault()
    const [isUploadOpen, setIsUploadOpen] = useState(false)
    const [previewFile, setPreviewFile] = useState<{ id: string, name: string, size: string, type: string, url?: string } | null>(null)
    const [conversations, setConversations] = useState<any[]>([])
    const router = useRouter()
    const searchParams = useSearchParams()
    const currentChatId = searchParams.get('chatId')

    useEffect(() => {
        if (project.id) {
            fetch(`/api/chat/conversations?projectId=${project.id}&limit=5`)
                .then(res => res.json())
                .then(data => {
                    if (Array.isArray(data)) {
                        setConversations(data)
                    }
                })
                .catch(err => console.error("Failed to load conversations", err))
        }
    }, [project.id])

    // Real file upload
    const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = e.target.files
        if (files) {
            Array.from(files).forEach(file => {
                addFileToProject(project.id, file)
            })
            setIsUploadOpen(false)
        }
    }

    const [searchQuery, setSearchQuery] = useState("")

    const filteredFiles = project.files.filter(file =>
        file.name.toLowerCase().includes(searchQuery.toLowerCase())
    )

    return (
        <div className="w-[300px] border-r flex flex-col h-full bg-muted/10" id="project-sidebar">
            <div className="p-4 flex flex-col gap-4">
                <div>
                    <h3 className="font-semibold text-lg truncate" title={project.title}>{project.title}</h3>
                    <p className="text-xs text-muted-foreground">{project.organization}</p>
                </div>

                <Button className="w-full gap-2" onClick={() => setIsUploadOpen(true)} id="project-upload-btn">
                    <Upload className="h-4 w-4" />
                    Upload Files
                </Button>

                <div className="relative">
                    <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                    <Input
                        placeholder="Search files..."
                        className="pl-8 h-9"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
            </div>

            <Separator />

            <div className="p-2 pb-0">
                <div className="flex items-center justify-between px-2 mb-2">
                    <h4 className="text-xs font-semibold text-muted-foreground">RECENT CHATS</h4>
                    <Button variant="ghost" size="icon" className="h-4 w-4" onClick={() => router.push(`/vault/${project.id}`)}>
                        <Plus className="h-3 w-3" />
                    </Button>
                </div>
                <div className="flex flex-col gap-1 mb-4">
                    {conversations.length === 0 ? (
                        <div className="text-xs text-muted-foreground px-2 py-2">No recent chats</div>
                    ) : (
                        conversations.map(chat => (
                            <div
                                key={chat.id}
                                className={`flex items-center gap-2 px-2 py-2 rounded-md cursor-pointer text-sm truncate ${currentChatId === chat.id ? 'bg-accent text-accent-foreground font-medium' : 'hover:bg-accent text-muted-foreground'}`}
                                onClick={() => router.push(`/vault/${project.id}?chatId=${chat.id}`)}
                            >
                                <MessageSquare className="h-4 w-4 shrink-0" />
                                <span className="truncate">{chat.title || 'New Conversation'}</span>
                            </div>
                        ))
                    )}
                </div>
            </div>

            <div className="p-2 pt-0">
                <h4 className="text-xs font-semibold text-muted-foreground px-2 mb-2">DATABASE ({filteredFiles.length})</h4>
                <div className="h-[calc(100vh-250px)] overflow-y-auto pr-2" id="project-files-list">
                    <div className="flex flex-col gap-1">
                        {filteredFiles.length === 0 ? (
                            <div className="text-sm text-muted-foreground text-center py-8 px-4 border border-dashed rounded-md mx-2">
                                <p>No files yet.</p>
                                <p className="text-xs mt-1">Upload documents to start analyzing.</p>
                            </div>
                        ) : (
                            filteredFiles.map(file => (
                                <div
                                    key={file.id}
                                    className={`flex items-center justify-between group px-2 py-2 rounded-md hover:bg-accent cursor-pointer text-sm ${file.isUploading ? 'opacity-70' : ''}`}
                                    onClick={() => !file.isUploading && setPreviewFile(file)}
                                >
                                    <div className="flex items-center gap-2 truncate flex-1">
                                        {file.isUploading ? (
                                            <Loader2 className="h-4 w-4 animate-spin text-muted-foreground shrink-0" />
                                        ) : (
                                            <FileText className="h-4 w-4 text-blue-500 shrink-0" />
                                        )}
                                        <span className="truncate">{file.name}</span>
                                    </div>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        disabled={file.isDeleting || file.isUploading}
                                        className={`h-6 w-6 ${file.isDeleting ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'} transition-opacity text-muted-foreground hover:text-destructive`}
                                        onClick={(e) => {
                                            e.stopPropagation()
                                            removeFileFromProject(project.id, file.id)
                                        }}
                                    >
                                        {file.isDeleting ? (
                                            <Loader2 className="h-3 w-3 animate-spin" />
                                        ) : (
                                            <Trash2 className="h-3 w-3" />
                                        )}
                                    </Button>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            </div>

            <Dialog open={isUploadOpen} onOpenChange={setIsUploadOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Upload Files</DialogTitle>
                        <DialogDescription>Add documents to your project database.</DialogDescription>
                    </DialogHeader>
                    <div className="flex items-center justify-center w-full">
                        <label htmlFor="dropzone-file" className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100 dark:bg-muted/50 dark:hover:bg-muted">
                            <div className="flex flex-col items-center justify-center pt-5 pb-6">
                                <Upload className="w-8 h-8 mb-2 text-gray-500" />
                                <p className="text-sm text-gray-500"><span className="font-semibold">Click to upload</span> or drag and drop</p>
                            </div>
                            <input id="dropzone-file" type="file" className="hidden" multiple onChange={handleFileUpload} />
                        </label>
                    </div>
                </DialogContent>
            </Dialog>

            {/* File Preview Dialog */}
            <Dialog open={!!previewFile} onOpenChange={(open) => !open && setPreviewFile(null)}>
                <DialogContent className="max-w-3xl h-[80vh] flex flex-col">
                    <DialogHeader>
                        <DialogTitle className="flex items-center gap-2">
                            <FileText className="h-5 w-5 text-blue-500" />
                            {previewFile?.name}
                        </DialogTitle>
                        <DialogDescription>
                            {previewFile?.size} • {previewFile?.type || 'Document'}
                        </DialogDescription>
                    </DialogHeader>
                    <div className="flex-1 bg-muted/20 border rounded-md p-0 flex flex-col items-center justify-center text-muted-foreground overflow-hidden relative">
                        {previewFile?.url ? (
                            <iframe
                                src={previewFile.url}
                                className="w-full h-full border-none bg-white"
                                title="File Preview"
                            />
                        ) : (
                            <div className="flex flex-col items-center justify-center p-8">
                                <FileText className="h-16 w-16 mb-4 opacity-20" />
                                <p>Preview not available.</p>
                                <div className="absolute inset-0 opacity-[0.03] pointer-events-none p-8 space-y-4">
                                    {Array.from({ length: 20 }).map((_, i) => {
                                        // Keep render pure: use deterministic widths.
                                        const width = `${60 + ((i * 17) % 41)}%` // 60–100%
                                        return (
                                            <div
                                                key={i}
                                                className="h-4 bg-current rounded w-full"
                                                style={{ width }}
                                            />
                                        )
                                    })}
                                </div>
                            </div>
                        )}
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setPreviewFile(null)}>Close Preview</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

import { NextResponse } from 'next/server'

/**
 * Standardized API error response
 */
export function apiError(message: string, status: number = 500, detail?: any) {
    console.error(`[API ERROR] status=${status} | message=${message}`, detail || '')
    return NextResponse.json({ error: message }, { status })
}

/**
 * Standardized AI success response (JSON)
 */
export function apiSuccess(data: any) {
    return NextResponse.json(data)
}

/**
 * Robust AI JSON parsing with fallback
 */
export function parseAIJSON(text: string, responseKey?: string): any {
    try {
        // Try direct parse
        return JSON.parse(text)
    } catch {
        // Try to find JSON block in markdown
        const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/{[\s\S]*}/)
        if (jsonMatch) {
            try {
                return JSON.parse(jsonMatch[1] || jsonMatch[0])
            } catch {
                // Return as wrapped object if still failing
            }
        }

        // Final fallback: wrap the raw text in the expected key
        return responseKey ? { [responseKey]: text } : { result: text }
    }
}
